funcDef:
process_EdgesBom(input: {
  program: string;
  typeElement: string;

  finalThickness: number;
  dims: { length: number; width: number };

  edges: {
    front: { klass: string; color: string };
    left: { klass: string; color: string };
    back: { klass: string; color: string };
    right: { klass: string; color: string };
  };

  joint: {
    selectable: boolean;
    selectedId?: string;
  };

  enableProcessing: boolean;
}): {

  // --------------------------------------------------
  // Basic edge data
  // --------------------------------------------------
  edgeCodes: {
    front: string;
    left: string;
    back: string;
    right: string;
  };

  // --------------------------------------------------
  // Joint data
  // --------------------------------------------------
  joint: {
    jointTypeId: string;
    frontLeft: string;
    leftBack: string;
    backRight: string;
    rightFront: string;
    shape: string;
    transition: string;
  };

  // --------------------------------------------------
  // Optional processings
  // --------------------------------------------------
  processing?: {
    cornerFrontLeft: string;
    cornerLeftBack: string;
    cornerBackRight: string;
    cornerRightFront: string;

    edgeFront: string;
    edgeLeft: string;
    edgeBack: string;
    edgeRight: string;
  };

  // --------------------------------------------------
  // Cutting overdimensions
  // --------------------------------------------------
  overmeasure: {
    length: number;
    width: number;
  };
}
